        #[cfg(feature = "firecrawl")]
        let t = t.with_firecrawl(&config.tools.web.firecrawl);
        tool_registry.register(Box::new(t));
    }
    #[cfg(feature = "firecrawl")]
    if let Some(t) =
        moltis_tools::firecrawl::FirecrawlScrapeTool::from_config(&config.tools.web.firecrawl)
    {
        tool_registry.register(Box::new(t));

