                    "type": "integer",
                    "minimum": 0,
                    "description": "Lines of leading context (content mode)."
                },
                "-C": {
                    "type": "integer",
                    "minimum": 0,
                    "description": "Lines of context on both sides (content mode)."
                },
                "multiline": {
                    "type": "boolean",
                    "description": "Enable multi-line mode (`.` matches newlines)."
                },
                "head_limit": {
                    "type": "integer",
                    "minimum": 1,
                    "description": "Maximum rows to return after offset."
                },
                "offset": {
                    "type": "integer",
                    "minimum": 0,
                    "description": "Skip this many rows before applying head_limit."
                }
            }
        })
    }

    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
        let pattern = params
            .get("pattern")
            .and_then(Value::as_str)
            .ok_or_else(|| Error::message("missing 'pattern' parameter"))?
            .to_string();

        let path = params
            .get("path")
            .and_then(Value::as_str)
            .map(PathBuf::from)
            .unwrap_or_else(|| PathBuf::from("."));

        let glob = params
            .get("glob")
            .and_then(Value::as_str)
            .map(|raw| -> Result<GlobMatcher> {
                Ok(GlobPattern::new(raw)
                    .map_err(|e| Error::message(format!("invalid glob '{raw}': {e}")))?
                    .compile_matcher())
            })
            .transpose()?;

        let file_type = params
            .get("type")
            .and_then(Value::as_str)
            .map(str::to_string);

        let output_mode =
            OutputMode::parse(params.get("output_mode").and_then(Value::as_str))?;

        let case_insensitive = params.get("-i").and_then(Value::as_bool).unwrap_or(false);
        let show_line_numbers = params.get("-n").and_then(Value::as_bool).unwrap_or(false);
        let context_symmetric = params
            .get("-C")
            .and_then(Value::as_u64)
            .map(|n| n as usize)
            .unwrap_or(0);
        let before_context = params
            .get("-B")
            .and_then(Value::as_u64)
            .map(|n| n as usize)
            .unwrap_or(context_symmetric);
        let after_context = params
            .get("-A")
            .and_then(Value::as_u64)
            .map(|n| n as usize)
            .unwrap_or(context_symmetric);
        let multiline = params
            .get("multiline")
            .and_then(Value::as_bool)
            .unwrap_or(false);
        let head_limit = params
            .get("head_limit")
            .and_then(Value::as_u64)
            .map(|n| n as usize);
        let offset = params
            .get("offset")
            .and_then(Value::as_u64)
            .map(|n| n as usize)
            .unwrap_or(0);

        let opts = GrepOptions {
            pattern,
            path,
            glob,
            file_type,
            output_mode,
            case_insensitive,
            show_line_numbers,
            before_context,
            after_context,
            multiline,
            head_limit,
            offset,
        };

        let self_owned = Self;
        let result =
            tokio::task::spawn_blocking(move || self_owned.grep_impl(opts))
                .await
                .map_err(|e| Error::message(format!("grep task failed: {e}")))?;

        match result {
            Ok(value) => {
                #[cfg(feature = "metrics")]
                metrics::counter!("moltis_fs_tool_calls_total", "tool" => "Grep", "outcome" => "ok")
                    .increment(1);
                Ok(value)
            },
            Err(e) => {
                #[cfg(feature = "metrics")]
                metrics::counter!("moltis_fs_tool_calls_total", "tool" => "Grep", "outcome" => "error")
                    .increment(1);
                Err(e.into())
            },
        }
    }
}

#[allow(clippy::unwrap_used, clippy::expect_used)]
#[cfg(test)]
mod tests {
    use super::*;

    async fn setup_tree() -> tempfile::TempDir {
        let dir = tempfile::tempdir().unwrap();
        tokio::fs::write(
            dir.path().join("lib.rs"),
            "fn alpha() {}\nfn beta() {}\nfn gamma() {}\n",
        )
        .await
        .unwrap();
        tokio::fs::write(dir.path().join("notes.md"), "alpha notes\nbeta notes\n")
            .await
            .unwrap();
        tokio::fs::write(dir.path().join("binary.bin"), [0u8, 1, 2, 3, 4, 5])
            .await
            .unwrap();
        dir
    }

    #[tokio::test]
    async fn grep_files_with_matches_default() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "beta",
                "path": dir.path().to_str().unwrap(),
            }))
            .await
            .unwrap();

        assert_eq!(value["mode"], "files_with_matches");
        let files: Vec<String> = value["files"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_str().unwrap().to_string())
            .collect();
        assert_eq!(files.len(), 2);
        assert!(files.iter().any(|p| p.ends_with("lib.rs")));
        assert!(files.iter().any(|p| p.ends_with("notes.md")));
    }

    #[tokio::test]
    async fn grep_count_mode() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "fn ",
                "path": dir.path().to_str().unwrap(),
                "output_mode": "count",
            }))
            .await
            .unwrap();

        let counts = value["counts"].as_array().unwrap();
        assert_eq!(counts.len(), 1);
        assert_eq!(counts[0]["count"], 3);
    }

    #[tokio::test]
    async fn grep_content_mode_with_line_numbers() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "beta",
                "path": dir.path().to_str().unwrap(),
                "output_mode": "content",
                "-n": true,
            }))
            .await
            .unwrap();

        let matches = value["matches"].as_array().unwrap();
        assert!(!matches.is_empty());
        let first = &matches[0];
        let block = first["block"].as_array().unwrap();
        assert!(block[0].as_str().unwrap().contains(':'));
    }

    #[tokio::test]
    async fn grep_case_insensitive() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "ALPHA",
                "path": dir.path().to_str().unwrap(),
                "-i": true,
            }))
            .await
            .unwrap();

        let files = value["files"].as_array().unwrap();
        assert_eq!(files.len(), 2);
    }

    #[tokio::test]
    async fn grep_glob_filter() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "alpha",
                "path": dir.path().to_str().unwrap(),
                "glob": "*.rs",
            }))
            .await
            .unwrap();

        let files = value["files"].as_array().unwrap();
        assert_eq!(files.len(), 1);
        assert!(files[0].as_str().unwrap().ends_with("lib.rs"));
    }

    #[tokio::test]
    async fn grep_type_filter() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "alpha",
                "path": dir.path().to_str().unwrap(),
                "type": "rust",
            }))
            .await
            .unwrap();

        let files = value["files"].as_array().unwrap();
        assert_eq!(files.len(), 1);
        assert!(files[0].as_str().unwrap().ends_with("lib.rs"));
    }

    #[tokio::test]
    async fn grep_head_limit_and_offset() {
        let dir = tempfile::tempdir().unwrap();
        for i in 0..5 {
            tokio::fs::write(dir.path().join(format!("f{i}.txt")), "match\n")
                .await
                .unwrap();
        }
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "match",
                "path": dir.path().to_str().unwrap(),
                "head_limit": 2,
                "offset": 1,
            }))
            .await
            .unwrap();

        let files = value["files"].as_array().unwrap();
        assert_eq!(files.len(), 2);
        assert_eq!(value["truncated"], true);
    }

    #[tokio::test]
    async fn grep_invalid_regex_errors() {
        let dir = tempfile::tempdir().unwrap();
        let tool = GrepTool::new();
        let err = tool
            .execute(json!({
                "pattern": "[invalid",
                "path": dir.path().to_str().unwrap(),
            }))
            .await
            .unwrap_err();
        assert!(err.to_string().contains("invalid regex"));
    }

    #[tokio::test]
    async fn grep_single_file_path() {
        let dir = setup_tree().await;
        let tool = GrepTool::new();
        let value = tool
            .execute(json!({
                "pattern": "alpha",
                "path": dir.path().join("lib.rs").to_str().unwrap(),
            }))
            .await
            .unwrap();

        let files = value["files"].as_array().unwrap();
        assert_eq!(files.len(), 1);
    }
}

