pub async fn canonicalize_existing(path: &str) -> Result<PathBuf> {
    require_absolute(path, "file_path")?;
    fs::canonicalize(path)
        .await
        .map_err(|e| Error::message(format!("cannot resolve path '{path}': {e}")))
}

