    async fn canonicalize_existing_resolves_file() {
        let mut tmp = tempfile::NamedTempFile::new().unwrap();
        tmp.write_all(b"hi").unwrap();
        let resolved = canonicalize_existing(tmp.path().to_str().unwrap())
            .await
            .unwrap();
        assert!(resolved.is_absolute());
    }

