        // 6-space padding minimum to match Claude Code's visual style.
        let pad_width = width.max(6);
        out.push_str(&format!("{line_number:>pad_width$}→{body}"));
        if truncated {
            out.push('…');
        }
        out.push('\n');
    }

    NumberedLines {
        text: out,
        total_lines,
        start_line: start,
        rendered_lines: visible.len(),
        truncated: end_exclusive < total_lines,
    }
}

