 67→        let server = bridge.server_name().to_string();
 68→        reg.register_mcp(Box::new(McpToolAdapter(bridge)), server);
 69→    }
 70→
 71→    if count > 0 {
 72→        info!(tools = count, "MCP tools synced into tool registry");
 73→    }
