            moltis_mcp::TransportType::StreamableHttp
        },
        Some(_) => moltis_mcp::TransportType::Stdio,
        None => existing
            .map(|cfg| cfg.transport)
            .unwrap_or(moltis_mcp::TransportType::Stdio),
    };

