        DEFAULT_MAX_READ_BYTES, DEFAULT_READ_LINE_LIMIT, FsErrorKind, format_numbered_lines,
        fs_error_payload, io_error_to_typed_payload, looks_binary, require_absolute,
    },
};

/// Native `Read` tool implementation.
#[derive(Default)]
pub struct ReadTool;

impl ReadTool {
    #[must_use]
