                if let Some(payload) = io_error_to_typed_payload(&e, file_path) {
                    return Ok(payload);
                }
                return Err(Error::message(format!("cannot stat '{file_path}': {e}")));
            },
        };

        if !meta.is_file() {
            return Ok(fs_error_payload(
                FsErrorKind::NotRegularFile,
                file_path,
                "path is not a regular file",
                None,
