        let content = "alpha\nbeta";
        let rendered = format_numbered_lines(content, 1, 100);
        assert_eq!(rendered.total_lines, 2);
        assert_eq!(rendered.rendered_lines, 2);
        assert_eq!(rendered.text, "     1→alpha\n     2→beta\n");
    }

