    async fn typed_not_found_survives_registry_dispatch() {
        let registry = build_registry(None);
        let read = registry.get("Read").unwrap();
        let v = read
            .execute(json!({ "file_path": "/tmp/does-not-exist-contract-99aa1" }))
            .await
            .unwrap();
        assert_eq!(v["kind"], "not_found");
    }
}

